// Get the webhook node which holds the original binaries
const formNode = $('Webhook').first();

// Get all current items flowing through
const items = $input.all();

// Build clean output items from scratch
const output = [];

for (const item of items) {
  // Build a fresh, properly structured item
  const newItem = {
    json: (item.json && typeof item.json === 'object' && !Array.isArray(item.json)) 
      ? item.json 
      : {},
    binary: item.binary || {}
  };

  // Copy ALL binary keys from the form trigger
  if (formNode.binary) {
    for (const key in formNode.binary) {
      newItem.binary[key] = formNode.binary[key];
    }
  }

  output.push(newItem);
}

return output;

